            <tr><td><code>push</code> (insert)</th><td>O(1)</th></tr>
            <tr><td><code>pop</code> (delete)</th><td>O(1)</th></tr>
            <tr><td><code>top</code> (peek)</th><td>O(1)</th></tr>
